// mob-sprites.js — Canvas 2D sprite functions for Clungiverse mobs
// Generated by BigClungus mob sprite pipeline.
// Each function: drawSprite_<slug>(ctx, cx, cy)
// Only ctx.fillStyle and ctx.fillRect. Character ~40px tall, centered on cx/cy.


// Cave Rat: hunched gray rodent with pink-lined ears, beady eyes, and a wiry tail
function drawSprite_cave_rat(ctx, cx, cy) {
  // Ears (outer, dark gray)
  ctx.fillStyle = '#5c5c5c';
  ctx.fillRect(cx - 8, cy - 20, 4, 7);
  ctx.fillRect(cx + 4, cy - 20, 4, 7);
  // Ears (inner, pink)
  ctx.fillStyle = '#b05868';
  ctx.fillRect(cx - 7, cy - 19, 2, 5);
  ctx.fillRect(cx + 5, cy - 19, 2, 5);
  // Head
  ctx.fillStyle = '#787878';
  ctx.fillRect(cx - 7, cy - 14, 14, 9);
  // Snout (tapered forward)
  ctx.fillStyle = '#858585';
  ctx.fillRect(cx - 4, cy - 8, 8, 3);
  ctx.fillRect(cx - 2, cy - 6, 4, 2);
  // Eyes
  ctx.fillStyle = '#0d0d0d';
  ctx.fillRect(cx - 5, cy - 13, 2, 2);
  ctx.fillRect(cx + 3, cy - 13, 2, 2);
  // Nose
  ctx.fillStyle = '#bb2222';
  ctx.fillRect(cx - 1, cy - 5, 2, 2);
  // Body (hunched)
  ctx.fillStyle = '#6a6a6a';
  ctx.fillRect(cx - 9, cy - 5, 18, 15);
  // Belly (lighter)
  ctx.fillStyle = '#959595';
  ctx.fillRect(cx - 5, cy - 2, 10, 8);
  // Front legs
  ctx.fillStyle = '#545454';
  ctx.fillRect(cx - 8, cy + 10, 4, 8);
  ctx.fillRect(cx + 4, cy + 10, 4, 8);
  // Feet
  ctx.fillStyle = '#444444';
  ctx.fillRect(cx - 9, cy + 16, 5, 2);
  ctx.fillRect(cx + 4, cy + 16, 5, 2);
  // Tail (right then curves down)
  ctx.fillStyle = '#7a6858';
  ctx.fillRect(cx + 9, cy + 3, 8, 2);
  ctx.fillRect(cx + 15, cy + 5, 2, 5);
  ctx.fillRect(cx + 13, cy + 9, 2, 4);
}


// Shadow Hound: crouching dark canine silhouette, crimson scent-tracker eyes, haunched hunting stance
function drawSprite_shadow_hound(ctx, cx, cy) {
  // Ears
  ctx.fillStyle = '#12061e';
  ctx.fillRect(cx - 7, cy - 20, 4, 8);
  ctx.fillRect(cx + 3, cy - 20, 4, 8);

  // Head
  ctx.fillStyle = '#251040';
  ctx.fillRect(cx - 8, cy - 14, 16, 9);

  // Snout
  ctx.fillStyle = '#180a2e';
  ctx.fillRect(cx - 5, cy - 8, 10, 5);

  // Glowing eyes (outer)
  ctx.fillStyle = '#cc1100';
  ctx.fillRect(cx - 5, cy - 12, 3, 3);
  ctx.fillRect(cx + 2, cy - 12, 3, 3);

  // Glowing eyes (inner highlight)
  ctx.fillStyle = '#ff4422';
  ctx.fillRect(cx - 4, cy - 11, 1, 1);
  ctx.fillRect(cx + 3, cy - 11, 1, 1);

  // Nose
  ctx.fillStyle = '#330a18';
  ctx.fillRect(cx - 2, cy - 4, 4, 2);

  // Neck
  ctx.fillStyle = '#1e0c36';
  ctx.fillRect(cx - 5, cy - 4, 10, 3);

  // Body
  ctx.fillStyle = '#2a1248';
  ctx.fillRect(cx - 9, cy - 2, 18, 12);

  // Body top ridge
  ctx.fillStyle = '#3c1a60';
  ctx.fillRect(cx - 7, cy - 2, 14, 4);

  // Body underside shadow
  ctx.fillStyle = '#0e0620';
  ctx.fillRect(cx - 9, cy + 8, 18, 2);

  // Tail (raised, back-right)
  ctx.fillStyle = '#1a0830';
  ctx.fillRect(cx + 9, cy - 4, 3, 4);
  ctx.fillRect(cx + 10, cy - 8, 3, 5);

  // Front legs
  ctx.fillStyle = '#1c0c30';
  ctx.fillRect(cx - 7, cy + 9, 4, 9);
  ctx.fillRect(cx - 1, cy + 9, 4, 9);

  // Back legs
  ctx.fillStyle = '#160a28';
  ctx.fillRect(cx + 3, cy + 9, 4, 9);

  // Paws
  ctx.fillStyle = '#0c061a';
  ctx.fillRect(cx - 8, cy + 17, 5, 3);
  ctx.fillRect(cx - 2, cy + 17, 5, 3);
  ctx.fillRect(cx + 2, cy + 17, 5, 3);
}


// Feral Stalker: crouched feral humanoid, arms dragging, hollow red eyes
function drawSprite_feral_stalker(ctx, cx, cy) {
    // Head — tilted forward, sunken
    ctx.fillStyle = '#4a2c1a';
    ctx.fillRect(cx - 4, cy - 20, 9, 7);

    // Sunken eye sockets
    ctx.fillStyle = '#1a0800';
    ctx.fillRect(cx - 3, cy - 19, 3, 3);
    ctx.fillRect(cx + 1, cy - 19, 3, 3);

    // Feral red glow in eyes
    ctx.fillStyle = '#dd1100';
    ctx.fillRect(cx - 2, cy - 18, 2, 2);
    ctx.fillRect(cx + 2, cy - 18, 2, 2);

    // Exposed teeth
    ctx.fillStyle = '#c8b89a';
    ctx.fillRect(cx - 2, cy - 14, 5, 1);
    ctx.fillStyle = '#1a0800';
    ctx.fillRect(cx - 1, cy - 14, 1, 1);
    ctx.fillRect(cx + 1, cy - 14, 1, 1);
    ctx.fillRect(cx + 3, cy - 14, 1, 1);

    // Neck
    ctx.fillStyle = '#3a2010';
    ctx.fillRect(cx - 2, cy - 13, 5, 3);

    // Hunched shoulders / upper back
    ctx.fillStyle = '#1e1008';
    ctx.fillRect(cx - 8, cy - 12, 17, 4);

    // Torso — ragged
    ctx.fillStyle = '#241408';
    ctx.fillRect(cx - 6, cy - 9, 13, 9);

    // Torn cloth patches on torso
    ctx.fillStyle = '#1a0c28';
    ctx.fillRect(cx - 5, cy - 8, 4, 3);
    ctx.fillRect(cx + 1, cy - 6, 4, 4);

    // Left upper arm — drooping low
    ctx.fillStyle = '#3a2010';
    ctx.fillRect(cx - 11, cy - 10, 4, 9);

    // Left forearm — reaching forward
    ctx.fillStyle = '#4a2c1a';
    ctx.fillRect(cx - 13, cy - 3, 4, 8);

    // Left claws
    ctx.fillStyle = '#b0a068';
    ctx.fillRect(cx - 15, cy + 4, 2, 5);
    ctx.fillRect(cx - 13, cy + 5, 2, 5);
    ctx.fillRect(cx - 11, cy + 4, 2, 5);

    // Right upper arm
    ctx.fillStyle = '#3a2010';
    ctx.fillRect(cx + 7, cy - 10, 4, 9);

    // Right forearm
    ctx.fillStyle = '#4a2c1a';
    ctx.fillRect(cx + 9, cy - 3, 4, 8);

    // Right claws
    ctx.fillStyle = '#b0a068';
    ctx.fillRect(cx + 11, cy + 4, 2, 5);
    ctx.fillRect(cx + 13, cy + 5, 2, 5);
    ctx.fillRect(cx + 15, cy + 4, 2, 5);

    // Left thigh — crouched stance
    ctx.fillStyle = '#1e1008';
    ctx.fillRect(cx - 6, cy, 5, 9);

    // Right thigh
    ctx.fillRect(cx + 1, cy, 5, 9);

    // Left shin — angled outward
    ctx.fillStyle = '#241408';
    ctx.fillRect(cx - 8, cy + 8, 5, 9);

    // Right shin
    ctx.fillRect(cx + 3, cy + 8, 5, 9);

    // Left foot
    ctx.fillStyle = '#100800';
    ctx.fillRect(cx - 9, cy + 17, 7, 3);

    // Right foot
    ctx.fillRect(cx + 2, cy + 17, 7, 3);

    // Mottled skin highlights
    ctx.fillStyle = '#5a3820';
    ctx.fillRect(cx - 1, cy - 19, 3, 2);
    ctx.fillRect(cx - 4, cy - 9, 2, 4);
    ctx.fillRect(cx - 12, cy - 2, 2, 3);
    ctx.fillRect(cx + 10, cy - 2, 2, 3);
}


// Fungal Spore: toxic mushroom cap with floating poison spore particles
function drawSprite_fungal_spore(ctx, cx, cy) {
    const x = cx - 10;
    const y = cy - 20;

    // Floating spore particles (chartreuse toxic)
    ctx.fillStyle = '#ADFF2F';
    ctx.fillRect(x + 2, y, 2, 2);
    ctx.fillRect(x + 11, y, 2, 2);
    ctx.fillRect(x + 17, y + 3, 2, 2);
    ctx.fillRect(x, y + 7, 2, 2);
    ctx.fillRect(x + 18, y + 9, 2, 2);

    // Cap top dome (deep purple)
    ctx.fillStyle = '#5B1A8B';
    ctx.fillRect(x + 6, y + 4, 8, 2);

    // Cap main body (bright purple)
    ctx.fillStyle = '#8B2FC9';
    ctx.fillRect(x + 4, y + 6, 12, 2);
    ctx.fillRect(x + 2, y + 8, 16, 6);

    // Cap highlight spots (pale lavender)
    ctx.fillStyle = '#DDB8FF';
    ctx.fillRect(x + 4, y + 8, 2, 2);
    ctx.fillRect(x + 10, y + 9, 2, 2);
    ctx.fillRect(x + 14, y + 8, 2, 2);

    // Gills underside (sickly green)
    ctx.fillStyle = '#5DBF4A';
    ctx.fillRect(x + 2, y + 14, 16, 2);

    // Toxic puff clouds flanking gills
    ctx.fillStyle = '#7FFF00';
    ctx.fillRect(x - 2, y + 13, 4, 4);
    ctx.fillRect(x + 18, y + 15, 4, 4);
    ctx.fillRect(x - 1, y + 20, 3, 3);
    ctx.fillRect(x + 18, y + 21, 3, 3);

    // Stem connector
    ctx.fillStyle = '#C8A87A';
    ctx.fillRect(x + 7, y + 16, 6, 2);

    // Stem body (tan)
    ctx.fillStyle = '#D4B896';
    ctx.fillRect(x + 8, y + 18, 4, 12);

    // Stem ring (green band)
    ctx.fillStyle = '#3A8E2A';
    ctx.fillRect(x + 7, y + 22, 6, 2);

    // Base bulb (dark purple-brown)
    ctx.fillStyle = '#6B3A5E';
    ctx.fillRect(x + 5, y + 30, 10, 4);
    ctx.fillRect(x + 6, y + 34, 8, 2);

    // Ground mycelium tendrils
    ctx.fillStyle = '#3E1A38';
    ctx.fillRect(x + 3, y + 35, 3, 2);
    ctx.fillRect(x + 8, y + 36, 4, 2);
    ctx.fillRect(x + 14, y + 35, 3, 2);
    ctx.fillRect(x + 2, y + 37, 2, 2);
    ctx.fillRect(x + 7, y + 38, 2, 2);
    ctx.fillRect(x + 12, y + 38, 2, 2);
    ctx.fillRect(x + 16, y + 37, 2, 2);
}


// Acid Sprayer: hunched toxic body with backpack tank and forward spray nozzle

function drawSprite_acid_sprayer(ctx, cx, cy) {
    // Poison tank (backpack)
    ctx.fillStyle = '#1a5c1a';
    ctx.fillRect(cx - 11, cy - 10, 5, 14);
    ctx.fillStyle = '#25aa25';
    ctx.fillRect(cx - 10, cy - 9, 2, 4);

    // Body
    ctx.fillStyle = '#2d6e1f';
    ctx.fillRect(cx - 6, cy - 12, 12, 20);
    // Belly
    ctx.fillStyle = '#4a9a30';
    ctx.fillRect(cx - 3, cy - 8, 6, 12);

    // Head
    ctx.fillStyle = '#3a7a25';
    ctx.fillRect(cx - 5, cy - 20, 10, 9);
    // Eye glow
    ctx.fillStyle = '#ddff00';
    ctx.fillRect(cx + 1, cy - 17, 3, 3);

    // Nozzle arm
    ctx.fillStyle = '#1a3d0f';
    ctx.fillRect(cx + 6, cy - 5, 9, 3);
    // Nozzle tip
    ctx.fillStyle = '#3a6a20';
    ctx.fillRect(cx + 14, cy - 7, 3, 7);

    // Acid spray droplets
    ctx.fillStyle = '#88ff00';
    ctx.fillRect(cx + 17, cy - 5, 3, 2);
    ctx.fillRect(cx + 20, cy - 7, 2, 2);
    ctx.fillRect(cx + 21, cy - 3, 2, 2);
    ctx.fillRect(cx + 20, cy - 1, 3, 2);
    ctx.fillRect(cx + 18, cy + 1, 2, 2);

    // Legs
    ctx.fillStyle = '#2d5a1a';
    ctx.fillRect(cx - 5, cy + 8, 4, 12);
    ctx.fillRect(cx + 1, cy + 8, 4, 12);
    // Feet
    ctx.fillStyle = '#1a3d0f';
    ctx.fillRect(cx - 6, cy + 18, 5, 3);
    ctx.fillRect(cx, cy + 18, 5, 3);
}


// Chaos Weaver: hooded arcane mage trailing scattered threads of chaotic energy

function drawSprite_chaos_weaver(ctx, cx, cy) {
  // Hood
  ctx.fillStyle = '#4a0e8f';
  ctx.fillRect(cx - 4, cy - 20, 8, 8);
  // Hood sides framing face
  ctx.fillStyle = '#2d0855';
  ctx.fillRect(cx - 4, cy - 14, 2, 5);
  ctx.fillRect(cx + 3, cy - 14, 2, 5);
  // Face
  ctx.fillStyle = '#d4a574';
  ctx.fillRect(cx - 2, cy - 14, 5, 5);
  // Glowing eyes
  ctx.fillStyle = '#ff33ff';
  ctx.fillRect(cx - 1, cy - 12, 1, 1);
  ctx.fillRect(cx + 2, cy - 12, 1, 1);
  // Upper robe
  ctx.fillStyle = '#3d0a6b';
  ctx.fillRect(cx - 4, cy - 9, 9, 10);
  // Lower robe flare
  ctx.fillStyle = '#2d0855';
  ctx.fillRect(cx - 6, cy + 1, 13, 10);
  // Robe hem
  ctx.fillStyle = '#1a033a';
  ctx.fillRect(cx - 8, cy + 11, 17, 5);
  // Feet
  ctx.fillStyle = '#150228';
  ctx.fillRect(cx - 7, cy + 16, 5, 4);
  ctx.fillRect(cx + 2, cy + 16, 5, 4);
  // Arms
  ctx.fillStyle = '#4a0e8f';
  ctx.fillRect(cx - 9, cy - 8, 5, 9);
  ctx.fillRect(cx + 5, cy - 8, 5, 9);
  // Hands
  ctx.fillStyle = '#d4a574';
  ctx.fillRect(cx - 8, cy + 1, 3, 3);
  ctx.fillRect(cx + 6, cy + 1, 3, 3);
  // Left energy orb (magenta)
  ctx.fillStyle = '#ff00ff';
  ctx.fillRect(cx - 11, cy - 1, 4, 4);
  ctx.fillStyle = '#ffaaff';
  ctx.fillRect(cx - 10, cy, 2, 2);
  // Right energy orb (cyan)
  ctx.fillStyle = '#00ccff';
  ctx.fillRect(cx + 8, cy - 1, 4, 4);
  ctx.fillStyle = '#aaeeff';
  ctx.fillRect(cx + 9, cy, 2, 2);
  // Chaos threads — magenta
  ctx.fillStyle = '#ff00ff';
  ctx.fillRect(cx - 15, cy - 7, 3, 1);
  ctx.fillRect(cx - 14, cy - 3, 2, 2);
  ctx.fillRect(cx - 13, cy + 5, 1, 3);
  // Chaos threads — cyan
  ctx.fillStyle = '#00ffff';
  ctx.fillRect(cx + 12, cy - 5, 3, 1);
  ctx.fillRect(cx + 13, cy, 2, 2);
  ctx.fillRect(cx + 12, cy + 6, 1, 3);
  // Chaos threads — gold
  ctx.fillStyle = '#ffcc00';
  ctx.fillRect(cx - 12, cy - 16, 2, 2);
  ctx.fillRect(cx + 10, cy - 15, 2, 2);
  ctx.fillRect(cx - 11, cy + 9, 2, 1);
  ctx.fillRect(cx + 9, cy + 10, 2, 1);
  // White spark cores
  ctx.fillStyle = '#ffffff';
  ctx.fillRect(cx - 16, cy - 5, 1, 1);
  ctx.fillRect(cx + 16, cy - 4, 1, 1);
  ctx.fillRect(cx - 1, cy - 19, 2, 1);
}


// Stone Golem: hulking rectangular mass of cracked granite blocks, glowing eye slits

function drawSprite_stone_golem(ctx, cx, cy) {
  // Shadow
  ctx.fillStyle = '#22222244';
  ctx.fillRect(cx - 10, cy + 19, 20, 3);

  // Legs
  ctx.fillStyle = '#5a5a5a';
  ctx.fillRect(cx - 8, cy + 8, 6, 12);
  ctx.fillRect(cx + 2, cy + 8, 6, 12);

  // Leg shading
  ctx.fillStyle = '#3d3d3d';
  ctx.fillRect(cx - 8, cy + 16, 6, 4);
  ctx.fillRect(cx + 2, cy + 16, 6, 4);

  // Body
  ctx.fillStyle = '#6e6e6e';
  ctx.fillRect(cx - 9, cy - 10, 18, 18);

  // Body block seams
  ctx.fillStyle = '#4a4a4a';
  ctx.fillRect(cx - 9, cy - 2, 18, 2);
  ctx.fillRect(cx - 1, cy - 10, 2, 18);

  // Mossy patches
  ctx.fillStyle = '#3a5c3a';
  ctx.fillRect(cx - 7, cy - 8, 3, 2);
  ctx.fillRect(cx + 3, cy + 1, 3, 2);

  // Body highlight
  ctx.fillStyle = '#8a8a8a';
  ctx.fillRect(cx - 9, cy - 10, 4, 6);

  // Arms
  ctx.fillStyle = '#636363';
  ctx.fillRect(cx - 14, cy - 9, 5, 15);
  ctx.fillRect(cx + 9, cy - 9, 5, 15);

  // Arm shading
  ctx.fillStyle = '#3d3d3d';
  ctx.fillRect(cx - 14, cy + 2, 5, 4);
  ctx.fillRect(cx + 9, cy + 2, 5, 4);

  // Fists
  ctx.fillStyle = '#5a5a5a';
  ctx.fillRect(cx - 15, cy + 6, 7, 6);
  ctx.fillRect(cx + 8, cy + 6, 7, 6);

  // Head
  ctx.fillStyle = '#727272';
  ctx.fillRect(cx - 6, cy - 20, 12, 11);

  // Head highlight
  ctx.fillStyle = '#8c8c8c';
  ctx.fillRect(cx - 6, cy - 20, 5, 4);

  // Head crack
  ctx.fillStyle = '#3a3a3a';
  ctx.fillRect(cx - 1, cy - 20, 1, 5);

  // Glowing eyes
  ctx.fillStyle = '#cc4400';
  ctx.fillRect(cx - 5, cy - 16, 3, 2);
  ctx.fillRect(cx + 2, cy - 16, 3, 2);

  // Eye glow
  ctx.fillStyle = '#ff6600';
  ctx.fillRect(cx - 4, cy - 16, 2, 1);
  ctx.fillRect(cx + 3, cy - 16, 2, 1);
}


// Iron Behemoth: hulking iron-plate golem with glowing red visor and massive fists
function drawSprite_iron_behemoth(ctx, cx, cy) {
  // helmet
  ctx.fillStyle = "#3a3a3a";
  ctx.fillRect(cx - 6, cy - 20, 12, 10);
  // visor slot
  ctx.fillStyle = "#1a1a1a";
  ctx.fillRect(cx - 5, cy - 16, 10, 4);
  // eyes
  ctx.fillStyle = "#c0392b";
  ctx.fillRect(cx - 4, cy - 15, 3, 2);
  ctx.fillRect(cx + 1, cy - 15, 3, 2);
  // shoulder guards
  ctx.fillStyle = "#505050";
  ctx.fillRect(cx - 12, cy - 10, 6, 5);
  ctx.fillRect(cx + 6,  cy - 10, 6, 5);
  // torso
  ctx.fillStyle = "#3a3a3a";
  ctx.fillRect(cx - 9, cy - 10, 18, 22);
  // chest plate
  ctx.fillStyle = "#5e5e5e";
  ctx.fillRect(cx - 7, cy - 8, 14, 9);
  // chest highlight
  ctx.fillStyle = "#7a7a7a";
  ctx.fillRect(cx - 5, cy - 7, 10, 3);
  // belly seam
  ctx.fillStyle = "#222";
  ctx.fillRect(cx - 6, cy + 2, 12, 2);
  // rivets (decorative dots via small rects)
  ctx.fillStyle = "#888";
  ctx.fillRect(cx - 6, cy - 9, 2, 2);
  ctx.fillRect(cx + 4, cy - 9, 2, 2);
  // left arm
  ctx.fillStyle = "#3a3a3a";
  ctx.fillRect(cx - 13, cy - 8, 5, 15);
  // right arm
  ctx.fillRect(cx + 8,  cy - 8, 5, 15);
  // left fist
  ctx.fillStyle = "#505050";
  ctx.fillRect(cx - 14, cy + 5, 6, 5);
  // right fist
  ctx.fillRect(cx + 8,  cy + 5, 6, 5);
  // legs
  ctx.fillStyle = "#3a3a3a";
  ctx.fillRect(cx - 8, cy + 12, 7, 8);
  ctx.fillRect(cx + 1, cy + 12, 7, 8);
  // feet (wide, heavy)
  ctx.fillStyle = "#505050";
  ctx.fillRect(cx - 9, cy + 18, 9, 2);
  ctx.fillRect(cx,     cy + 18, 9, 2);
}


// Abyssal Titan: hulking void-armored colossus with cracked teal core and crushing fists
function drawSprite_abyssal_titan(ctx, cx, cy) {
    // Horns
    ctx.fillStyle = "#0a0015";
    ctx.fillRect(cx - 7, cy - 23, 3, 5);
    ctx.fillRect(cx + 4, cy - 23, 3, 5);

    // Head
    ctx.fillStyle = "#1a0a2e";
    ctx.fillRect(cx - 5, cy - 20, 10, 9);

    // Eyes
    ctx.fillStyle = "#00e5cc";
    ctx.fillRect(cx - 4, cy - 18, 2, 2);
    ctx.fillRect(cx + 2, cy - 18, 2, 2);

    // Jaw shadow
    ctx.fillStyle = "#0d0520";
    ctx.fillRect(cx - 4, cy - 13, 8, 2);

    // Shoulders (wide pauldrons)
    ctx.fillStyle = "#0d0520";
    ctx.fillRect(cx - 11, cy - 11, 22, 5);

    // Shoulder studs
    ctx.fillStyle = "#1a0a2e";
    ctx.fillRect(cx - 11, cy - 11, 4, 4);
    ctx.fillRect(cx + 7, cy - 11, 4, 4);

    // Torso
    ctx.fillStyle = "#1a0a2e";
    ctx.fillRect(cx - 8, cy - 6, 16, 15);

    // Void crack (chest core)
    ctx.fillStyle = "#002233";
    ctx.fillRect(cx - 3, cy - 4, 6, 10);
    ctx.fillStyle = "#00e5cc";
    ctx.fillRect(cx - 1, cy - 2, 2, 6);

    // Arms
    ctx.fillStyle = "#0d0520";
    ctx.fillRect(cx - 13, cy - 9, 5, 16);
    ctx.fillRect(cx + 8, cy - 9, 5, 16);

    // Fists
    ctx.fillStyle = "#1a0a2e";
    ctx.fillRect(cx - 14, cy + 6, 6, 5);
    ctx.fillRect(cx + 8, cy + 6, 6, 5);

    // Fist knuckle glow
    ctx.fillStyle = "#00e5cc";
    ctx.fillRect(cx - 13, cy + 6, 4, 1);
    ctx.fillRect(cx + 9, cy + 6, 4, 1);

    // Legs
    ctx.fillStyle = "#150825";
    ctx.fillRect(cx - 7, cy + 9, 6, 9);
    ctx.fillRect(cx + 1, cy + 9, 6, 9);

    // Feet
    ctx.fillStyle = "#0d0520";
    ctx.fillRect(cx - 8, cy + 17, 7, 3);
    ctx.fillRect(cx + 1, cy + 17, 7, 3);
}

// Explicit window registration — ensures all sprite functions are accessible
// via window['drawSprite_<slug>'] even in strict-mode or module contexts.
window.drawSprite_cave_rat = drawSprite_cave_rat;
window.drawSprite_shadow_hound = drawSprite_shadow_hound;
window.drawSprite_feral_stalker = drawSprite_feral_stalker;
window.drawSprite_fungal_spore = drawSprite_fungal_spore;
window.drawSprite_acid_sprayer = drawSprite_acid_sprayer;
window.drawSprite_chaos_weaver = drawSprite_chaos_weaver;
window.drawSprite_stone_golem = drawSprite_stone_golem;
window.drawSprite_iron_behemoth = drawSprite_iron_behemoth;
window.drawSprite_abyssal_titan = drawSprite_abyssal_titan;
